            .json()
            .try_init();
    });
}

fn run_entrypoint(args: impl IntoIterator<Item = OsString>) -> i32 {
    let cli = match parse_cli_from(args) {
        Ok(cli) => cli,
        Err(err) => {
            eprintln!("{err}");
            return 2;
        }
